"use client"

import { TransactionHistoryUI } from "./transaction-history-ui"
import {
  useTransactionHistory,
  type HistoryEntry,
  type UseTransactionHistoryOptions,
} from "./use-transaction-history"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export {
  TransactionHistoryUI,
  type TransactionHistoryUIProps,
} from "./transaction-history-ui"
export {
  useTransactionHistory,
  type UseTransactionHistoryOptions,
  type UseTransactionHistoryReturn,
  type HistoryEntry,
  type TransactionStatus,
} from "./use-transaction-history"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Props for the composed TransactionHistory block */
export interface TransactionHistoryProps {
  /** BSV payment address to fetch transaction history for */
  address?: string | null
  /** Pre-loaded transaction entries (bypasses API fetch) */
  entries?: HistoryEntry[]
  /** Custom API base URL (default: https://api.1sat.app) */
  apiUrl?: string
  /** Number of entries per page (default: 20) */
  pageSize?: number
  /** Whether to auto-fetch on mount (default: true) */
  autoFetch?: boolean
  /** Callback when a row is clicked */
  onRowClick?: (txid: string) => void
  /** Callback for external link button */
  onExternalLink?: (url: string) => void
  /** Callback fired on successful fetch */
  onSuccess?: (entries: HistoryEntry[]) => void
  /** Callback fired on fetch error */
  onError?: (error: Error) => void
  /** Visual variant: "default" shows full details, "compact" shows description + amount only */
  variant?: "default" | "compact"
  /** Number of skeleton rows to show while loading (default: 5) */
  skeletonCount?: number
  /** Optional CSS class name */
  className?: string
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * Transaction history list with status indicators, amounts, and relative
 * dates. Displays inbound/outbound transactions with pagination support.
 *
 * Composes the `useTransactionHistory` hook with the `TransactionHistoryUI`
 * presentation component. Pass `entries` to use pre-loaded data, or
 * `address` to fetch from the 1sat-stack API.
 *
 * @example
 * ```tsx
 * import { TransactionHistory } from "@/components/blocks/transaction-history"
 *
 * function WalletActivity() {
 *   return (
 *     <TransactionHistory
 *       address="1A1zP1eP5QGefi2DMPTfTL5SLmv7DivfNa"
 *       onRowClick={(txid) => console.log("Clicked:", txid)}
 *     />
 *   )
 * }
 * ```
 */
export function TransactionHistory({
  address,
  entries: externalEntries,
  apiUrl,
  pageSize,
  autoFetch,
  onRowClick,
  onExternalLink,
  onSuccess,
  onError,
  variant,
  skeletonCount,
  className,
}: TransactionHistoryProps) {
  const hookOptions: UseTransactionHistoryOptions = {
    address,
    entries: externalEntries,
    apiUrl,
    pageSize,
    autoFetch,
    onSuccess,
    onError,
  }

  const { entries, isLoading, error, hasMore, loadMore } =
    useTransactionHistory(hookOptions)

  return (
    <TransactionHistoryUI
      entries={entries}
      isLoading={isLoading}
      error={error}
      hasMore={hasMore}
      onLoadMore={loadMore}
      onRowClick={onRowClick}
      onExternalLink={onExternalLink}
      variant={variant}
      skeletonCount={skeletonCount}
      className={className}
    />
  )
}

"use client"

import { useCallback } from "react"
import { ArrowDownLeft, ArrowUpRight, ExternalLink, History, Loader2 } from "lucide-react"
import { cn } from "@/lib/utils"
import { Card, CardContent } from "@/components/ui/card"
import { Separator } from "@/components/ui/separator"
import { Skeleton } from "@/components/ui/skeleton"
import { Button } from "@/components/ui/button"
import type { HistoryEntry, TransactionStatus } from "./use-transaction-history"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Props for the TransactionHistoryUI presentation component */
export interface TransactionHistoryUIProps {
  /** Transaction entries to display */
  entries: HistoryEntry[]
  /** Whether the list is loading */
  isLoading: boolean
  /** Error from the last fetch attempt */
  error: Error | null
  /** Whether more entries can be loaded */
  hasMore?: boolean
  /** Load the next page of entries */
  onLoadMore?: () => void
  /** Callback when a row is clicked */
  onRowClick?: (txid: string) => void
  /** Callback for external link button (e.g. open in block explorer) */
  onExternalLink?: (url: string) => void
  /** Visual variant: "default" shows full details, "compact" shows description + amount only */
  variant?: "default" | "compact"
  /** Number of skeleton rows to show while loading (default: 5) */
  skeletonCount?: number
  /** Optional CSS class name */
  className?: string
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Status dot color mapping using semantic tokens */
function statusDotClass(status: TransactionStatus): string {
  switch (status) {
    case "completed":
      return "bg-chart-2"
    case "sending":
    case "unproven":
      return "bg-chart-4"
    case "failed":
      return "bg-destructive"
  }
}

/** Status label for screen readers */
function statusLabel(status: TransactionStatus): string {
  switch (status) {
    case "completed":
      return "Completed"
    case "sending":
      return "Sending"
    case "unproven":
      return "Unproven"
    case "failed":
      return "Failed"
  }
}

/** Format satoshi amount for display */
function formatSatoshis(satoshis: number): string {
  const abs = Math.abs(satoshis)
  if (abs >= 100_000_000) {
    return `${(satoshis / 100_000_000).toFixed(8)} BSV`
  }
  return `${satoshis.toLocaleString()} sat`
}

/** Truncate a txid for display */
function truncateTxid(txid: string): string {
  if (txid.length <= 16) return txid
  return `${txid.slice(0, 8)}...${txid.slice(-6)}`
}

/** Relative time from an ISO date string */
function relativeTime(isoDate: string): string {
  const now = Date.now()
  const then = new Date(isoDate).getTime()
  const diffMs = now - then

  const seconds = Math.floor(diffMs / 1000)
  if (seconds < 60) return "just now"

  const minutes = Math.floor(seconds / 60)
  if (minutes < 60) return `${minutes}m ago`

  const hours = Math.floor(minutes / 60)
  if (hours < 24) return `${hours}h ago`

  const days = Math.floor(hours / 24)
  if (days < 30) return `${days}d ago`

  const months = Math.floor(days / 30)
  if (months < 12) return `${months}mo ago`

  const years = Math.floor(months / 12)
  return `${years}y ago`
}

// ---------------------------------------------------------------------------
// Sub-components
// ---------------------------------------------------------------------------

interface TransactionRowProps {
  entry: HistoryEntry
  variant: "default" | "compact"
  onRowClick?: (txid: string) => void
  onExternalLink?: (url: string) => void
  isLast: boolean
}

function TransactionRow({
  entry,
  variant,
  onRowClick,
  onExternalLink,
  isLast,
}: TransactionRowProps) {
  const isInbound = entry.satoshis >= 0
  const isInteractive = !!onRowClick

  const handleClick = useCallback(() => {
    onRowClick?.(entry.txid)
  }, [onRowClick, entry.txid])

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault()
        onRowClick?.(entry.txid)
      }
    },
    [onRowClick, entry.txid]
  )

  const handleExternalClick = useCallback(
    (e: React.MouseEvent) => {
      e.stopPropagation()
      onExternalLink?.(entry.txid)
    },
    [onExternalLink, entry.txid]
  )

  return (
    <>
      <div
        role={isInteractive ? "button" : undefined}
        tabIndex={isInteractive ? 0 : undefined}
        className={cn(
          "flex items-center gap-3 px-4 py-3",
          isInteractive &&
            "cursor-pointer transition-colors hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-md"
        )}
        onClick={isInteractive ? handleClick : undefined}
        onKeyDown={isInteractive ? handleKeyDown : undefined}
        aria-label={
          isInteractive
            ? `${entry.description}, ${formatSatoshis(entry.satoshis)}, ${statusLabel(entry.status)}`
            : undefined
        }
      >
        {/* Direction icon + status dot */}
        <div className="relative flex-shrink-0">
          <div
            className={cn(
              "flex items-center justify-center size-9 rounded-full",
              isInbound
                ? "bg-chart-2/10 text-chart-2"
                : "bg-muted text-muted-foreground"
            )}
          >
            {isInbound ? (
              <ArrowDownLeft className="size-4" data-icon aria-hidden="true" />
            ) : (
              <ArrowUpRight className="size-4" data-icon aria-hidden="true" />
            )}
          </div>
          <span
            className={cn(
              "absolute -bottom-0.5 -right-0.5 size-2.5 rounded-full border-2 border-background",
              statusDotClass(entry.status)
            )}
            aria-label={statusLabel(entry.status)}
          />
        </div>

        {/* Description + txid */}
        <div className="flex-1 min-w-0">
          <p className="text-sm font-medium text-foreground truncate">
            {entry.description}
          </p>
          {variant === "default" && (
            <div className="flex items-center gap-1.5">
              <span className="text-xs text-muted-foreground font-mono truncate">
                {truncateTxid(entry.txid)}
              </span>
              {onExternalLink && (
                <button
                  type="button"
                  onClick={handleExternalClick}
                  className="text-muted-foreground hover:text-foreground transition-colors flex-shrink-0"
                  aria-label={`Open transaction ${truncateTxid(entry.txid)} in explorer`}
                >
                  <ExternalLink className="size-3" data-icon aria-hidden="true" />
                </button>
              )}
            </div>
          )}
        </div>

        {/* Amount + date */}
        <div className="flex flex-col items-end gap-0.5 flex-shrink-0">
          <span
            className={cn(
              "text-sm font-semibold tabular-nums",
              isInbound ? "text-chart-2" : "text-foreground"
            )}
          >
            {isInbound ? "+" : ""}
            {formatSatoshis(entry.satoshis)}
          </span>
          {variant === "default" && (
            <span className="text-xs text-muted-foreground">
              {relativeTime(entry.dateCreated)}
            </span>
          )}
        </div>
      </div>
      {!isLast && <Separator />}
    </>
  )
}

function SkeletonRow({
  variant,
  isLast,
}: {
  variant: "default" | "compact"
  isLast: boolean
}) {
  return (
    <>
      <div className="flex items-center gap-3 px-4 py-3">
        <Skeleton className="size-9 rounded-full flex-shrink-0" />
        <div className="flex-1 flex flex-col gap-1.5">
          <Skeleton className="h-4 w-32" />
          {variant === "default" && <Skeleton className="h-3 w-24" />}
        </div>
        <div className="flex flex-col items-end gap-1.5">
          <Skeleton className="h-4 w-20" />
          {variant === "default" && <Skeleton className="h-3 w-12" />}
        </div>
      </div>
      {!isLast && <Separator />}
    </>
  )
}

// ---------------------------------------------------------------------------
// Main UI
// ---------------------------------------------------------------------------

/**
 * Pure presentation component for a list of transaction history entries.
 *
 * Renders loading skeletons, an empty state, an error state, or the
 * transaction rows with optional "Load more" pagination. Supports
 * "default" (full detail) and "compact" (description + amount) variants.
 */
export function TransactionHistoryUI({
  entries,
  isLoading,
  error,
  hasMore = false,
  onLoadMore,
  onRowClick,
  onExternalLink,
  variant = "default",
  skeletonCount = 5,
  className,
}: TransactionHistoryUIProps) {
  // Loading state (initial)
  if (isLoading && entries.length === 0) {
    return (
      <Card className={cn("w-full", className)}>
        <CardContent className="p-0">
          {Array.from({ length: skeletonCount }, (_, i) => (
            <SkeletonRow
              key={`skeleton-${i}`}
              variant={variant}
              isLast={i === skeletonCount - 1}
            />
          ))}
        </CardContent>
      </Card>
    )
  }

  // Error state
  if (error) {
    return (
      <Card className={cn("w-full", className)}>
        <CardContent className="flex flex-col items-center gap-2 py-10">
          <History
            className="size-10 text-destructive/60"
            aria-hidden="true"
          />
          <p className="text-sm font-medium text-destructive">
            Failed to load transactions
          </p>
          <p className="text-xs text-muted-foreground">{error.message}</p>
        </CardContent>
      </Card>
    )
  }

  // Empty state
  if (entries.length === 0) {
    return (
      <Card className={cn("w-full", className)}>
        <CardContent className="flex flex-col items-center gap-2 py-10">
          <History
            className="size-10 text-muted-foreground/50"
            aria-hidden="true"
          />
          <p className="text-sm text-muted-foreground">No transactions yet</p>
        </CardContent>
      </Card>
    )
  }

  // Transaction list
  return (
    <Card className={cn("w-full overflow-hidden", className)}>
      <CardContent className="p-0">
        {entries.map((entry, index) => (
          <TransactionRow
            key={entry.txid}
            entry={entry}
            variant={variant}
            onRowClick={onRowClick}
            onExternalLink={onExternalLink}
            isLast={index === entries.length - 1 && !hasMore}
          />
        ))}
        {hasMore && (
          <>
            <Separator />
            <div className="flex justify-center py-3">
              <Button
                variant="ghost"
                size="sm"
                onClick={onLoadMore}
                disabled={isLoading}
              >
                {isLoading ? (
                  <Loader2 className="size-4 animate-spin" data-icon aria-hidden="true" />
                ) : null}
                {isLoading ? "Loading..." : "Load more"}
              </Button>
            </div>
          </>
        )}
      </CardContent>
    </Card>
  )
}

import { useCallback, useEffect, useRef, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Transaction status */
export type TransactionStatus = "completed" | "unproven" | "sending" | "failed"

/** A single transaction history entry */
export interface HistoryEntry {
  /** Transaction ID */
  txid: string
  /** Human-readable description */
  description: string
  /** Amount in satoshis (positive = inbound, negative = outbound) */
  satoshis: number
  /** Current transaction status */
  status: TransactionStatus
  /** ISO-8601 date string */
  dateCreated: string
}

/** Shape returned from the 1sat-stack transaction endpoint */
interface TxHistoryApiEntry {
  txid: string
  description: string
  satoshis: number
  status: string
  dateCreated: string
}

/** Shape returned from the 1sat-stack history list endpoint */
interface TxHistoryApiResponse {
  entries: TxHistoryApiEntry[]
  hasMore: boolean
}

/** Options for the useTransactionHistory hook */
export interface UseTransactionHistoryOptions {
  /** BSV payment address to fetch transaction history for */
  address?: string | null
  /** Pre-loaded entries (bypasses API fetch when provided) */
  entries?: HistoryEntry[]
  /** Custom API base URL (default: https://api.1sat.app) */
  apiUrl?: string
  /** Number of entries per page (default: 20) */
  pageSize?: number
  /** Whether to auto-fetch on mount (default: true) */
  autoFetch?: boolean
  /** Callback fired on successful fetch */
  onSuccess?: (entries: HistoryEntry[]) => void
  /** Callback fired on fetch error */
  onError?: (error: Error) => void
}

/** Return value of the useTransactionHistory hook */
export interface UseTransactionHistoryReturn {
  /** List of transaction history entries */
  entries: HistoryEntry[]
  /** Whether the initial fetch is in progress */
  isLoading: boolean
  /** Error from the last fetch attempt */
  error: Error | null
  /** Whether more entries can be loaded */
  hasMore: boolean
  /** Load the next page of entries */
  loadMore: () => void
  /** Manually trigger a refetch from the beginning */
  refetch: () => void
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const DEFAULT_API_URL = "https://api.1sat.app"
const DEFAULT_PAGE_SIZE = 20

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function parseStatus(raw: string): TransactionStatus {
  switch (raw) {
    case "completed":
    case "unproven":
    case "sending":
    case "failed":
      return raw
    default:
      return "unproven"
  }
}

function mapApiEntry(entry: TxHistoryApiEntry): HistoryEntry {
  return {
    txid: entry.txid,
    description: entry.description,
    satoshis: entry.satoshis,
    status: parseStatus(entry.status),
    dateCreated: entry.dateCreated,
  }
}

async function fetchJson<T>(url: string, signal?: AbortSignal): Promise<T> {
  const res = await fetch(url, { signal })
  if (!res.ok) {
    throw new Error(`HTTP ${res.status}: ${url}`)
  }
  return res.json() as Promise<T>
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Fetches transaction history for a BSV address from the 1sat-stack API,
 * or accepts pre-loaded entries via the `entries` prop.
 *
 * Supports pagination with `loadMore` and manual `refetch`.
 *
 * @example
 * ```ts
 * const { entries, isLoading, error, hasMore, loadMore } = useTransactionHistory({
 *   address: "1A1zP1eP5QGefi2DMPTfTL5SLmv7DivfNa",
 * })
 * ```
 */
export function useTransactionHistory(
  options: UseTransactionHistoryOptions = {}
): UseTransactionHistoryReturn {
  const {
    address,
    entries: externalEntries,
    apiUrl = DEFAULT_API_URL,
    pageSize = DEFAULT_PAGE_SIZE,
    autoFetch = true,
    onSuccess,
    onError,
  } = options

  const [entries, setEntries] = useState<HistoryEntry[]>(externalEntries ?? [])
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<Error | null>(null)
  const [hasMore, setHasMore] = useState(false)
  const [offset, setOffset] = useState(0)
  const abortRef = useRef<AbortController | null>(null)

  // Sync external entries when they change
  useEffect(() => {
    if (externalEntries) {
      setEntries(externalEntries)
      setHasMore(false)
      setError(null)
    }
  }, [externalEntries])

  const fetchPage = useCallback(
    async (pageOffset: number, append: boolean) => {
      if (!address) return

      abortRef.current?.abort()
      const controller = new AbortController()
      abortRef.current = controller

      setIsLoading(true)
      setError(null)

      try {
        const data = await fetchJson<TxHistoryApiResponse>(
          `${apiUrl}/1sat/owner/${address}/tx-history?limit=${pageSize}&offset=${pageOffset}`,
          controller.signal
        )

        const mapped = data.entries.map(mapApiEntry)
        setEntries((prev) => (append ? [...prev, ...mapped] : mapped))
        setHasMore(data.hasMore)
        setOffset(pageOffset + mapped.length)
        onSuccess?.(mapped)
      } catch (err) {
        if (err instanceof DOMException && err.name === "AbortError") return
        const fetchError =
          err instanceof Error
            ? err
            : new Error("Failed to fetch transaction history")
        setError(fetchError)
        onError?.(fetchError)
      } finally {
        setIsLoading(false)
      }
    },
    [address, apiUrl, pageSize, onSuccess, onError]
  )

  const refetch = useCallback(() => {
    setOffset(0)
    setEntries([])
    void fetchPage(0, false)
  }, [fetchPage])

  const loadMore = useCallback(() => {
    if (!isLoading && hasMore) {
      void fetchPage(offset, true)
    }
  }, [isLoading, hasMore, offset, fetchPage])

  // Auto-fetch on mount / address change (only when no external entries)
  useEffect(() => {
    if (autoFetch && address && !externalEntries) {
      setOffset(0)
      void fetchPage(0, false)
    }

    return () => {
      abortRef.current?.abort()
    }
  }, [autoFetch, address, externalEntries, fetchPage])

  return {
    entries,
    isLoading,
    error,
    hasMore,
    loadMore,
    refetch,
  }
}
